#include <stdio.h>

int reverseInteger(int n) {
    int rev = 0, remainder;
    while (n != 0) {
        remainder = n % 10;
        rev = rev * 10 + remainder;
        n /= 10;
    }
    return rev;
}

int main() {
    printf("Reversed 12345: %d\n", reverseInteger(12345));
    return 0;
}

